import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import API_PATHS from 'lib/http/apiPaths';
import { optionLabelByValue, useParcelOptions, usePersonOptions } from 'features/shared/selectOptionHelpers';

export default function ResidentsPage() {
  const parcelOptions = useParcelOptions();
  const personOptions = usePersonOptions();

  return (
    <CrudResourceModule
      title="Residentes"
      path={API_PATHS.residents}
      columns={[
        { key: 'parcela', label: 'Parcela', render: (row) => optionLabelByValue(parcelOptions, row.parcela) },
        { key: 'persona', label: 'Persona', render: (row) => row.persona?.nombre_completo || 'Sin persona' },
        { key: 'tipo_residencia', label: 'Tipo' },
        {
          key: 'is_active',
          label: 'Activo',
          render: (row) => <Chip size="small" label={row.is_active ? 'Sí' : 'No'} color={row.is_active ? 'success' : 'default'} />
        }
      ]}
      fields={[
        { name: 'parcela', label: 'Parcela', type: 'select', required: true, options: parcelOptions },
        { name: 'persona_id', label: 'Persona (opcional)', type: 'select', options: personOptions },
        {
          name: 'tipo_residencia',
          label: 'Tipo residencia',
          type: 'select',
          required: true,
          options: [
            { value: 'RESIDENTE', label: 'Residente' },
            { value: 'CUIDADOR', label: 'Cuidador' },
            { value: 'FAMILIAR', label: 'Familiar' },
            { value: 'OTRO', label: 'Otro' }
          ]
        },
        { name: 'is_active', label: 'Activo', type: 'checkbox', defaultValue: true },
        { name: 'observaciones', label: 'Observaciones', type: 'textarea', fullWidth: true }
      ]}
      defaultOrdering="-created_at"
      searchPlaceholder="Buscar residentes por parcela o persona"
    />
  );
}
